		return nil, err
	}

	workspaceDir, err := setWorkspace(config.Workspace)
	if err != nil {
		return nil, err
	}

	server := &Server{
		engine:       engine,
		config:       config,
		authManager:  authManager,
		startTime:    time.Now(),
		workspaceDir: workspaceDir,
	}

	server.registerRoutes()

	return server, nil
}

func (s *Server) registerRoutes() {
	api := s.engine.Group("/api")
	api.Use(s.authManager.AuthMiddleware())
	{
		api.POST("/execute", s.ExecuteHandler)
		api.POST("/files", s.UploadFileHandler)
		api.GET("/files", s.ListFilesHandler)
		api.GET("/files/*path", s.DownloadFileHandler)
	}

	s.engine.GET("/health", s.HealthCheckHandler)
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv(PublicKeyEnvVar)
	if keyData == "" {
		return fmt.Errorf("environment variable %s is not set", PublicKeyEnvVar)
	}

	block, _ := pem.Decode([]byte(keyData))
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("public key is not RSA")
	}

	am.mutex.Lock()
	am.publicKey = rsaPub
	am.mutex.Unlock()

	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Authorization header is required",
				"code":   401,
				"detail": "Missing Authorization header",
			})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid authorization format",
				"code":   401,
				"detail": "Use Bearer <token>",
			})
			c.Abort()
			return
		}

		tokenString := parts[1]

		am.mutex.RLock()
		publicKey := am.publicKey
		am.mutex.RUnlock()

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid token",
				"code":   401,
				"detail": err.Error(),
			})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

func (s *Server) HealthCheckHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "PicoD",
		"version": "0.0.1",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid request body",
			"code":  400,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "command cannot be empty",
			"code":  400,
		})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		parsed, err := time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("invalid timeout format: %v", err),
				"code":  400,
			})
			return
		}
		timeout = parsed
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd, err := s.buildCommand(ctx, &req)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid working directory: %v", err),
			"code":  400,
		})
		return
	}

	if req.Env != nil {
		cmd.Env = append(os.Environ(), envMapToSlice(req.Env)...)
	}

	stdout := &bytes.Buffer{}
	stderr := &bytes.Buffer{}
	cmd.Stdout = stdout
	cmd.Stderr = stderr

	startTime := time.Now()
	err = cmd.Run()
	endTime := time.Now()
	duration := endTime.Sub(startTime).Seconds()

	response := ExecuteResponse{
		Stdout:    stdout.String(),
		Stderr:    stderr.String(),
		Duration:  duration,
		StartTime: startTime,
		EndTime:   endTime,
	}

	if ctx.Err() == context.DeadlineExceeded {
		response.ExitCode = TimeoutExitCode
		response.Stderr = fmt.Sprintf("Command timed out after %d seconds\n", int(duration))
	} else if cmd.ProcessState != nil {
		response.ExitCode = cmd.ProcessState.ExitCode()
	} else {
		response.ExitCode = 1
		if stderr.Len() > 0 {
			response.Stderr += "\n" + err.Error()
		} else {
			response.Stderr = err.Error()
		}
	}

	c.JSON(http.StatusOK, response)
}

func (s *Server) buildCommand(ctx context.Context, req *ExecuteRequest) (*exec.Cmd, error) {
	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	if req.WorkingDir != "" {
		workingDir, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			return nil, err
		}
		cmd.Dir = workingDir
	}

	return cmd, nil
}

func (s *Server) UploadFileHandler(c *gin.Context) {
	contentType := c.ContentType()

	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
	} else {
		s.handleJSONBase64Upload(c)
	}
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("file upload failed: %v", err),
			"code":  400,
		})
		return
	}

	src, err := file.Open()
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("failed to open uploaded file: %v", err),
			"code":  400,
		})
		return
	}
	defer src.Close()

	modeStr := c.PostForm("mode")
	mode := parseFileMode(modeStr)

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directories: %v", err),
			"code":  500,
		})
		return
	}

	dst, err := os.OpenFile(sanitizedPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create file: %v", err),
			"code":  500,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	fileInfo, _ := os.Stat(sanitizedPath)

	relPath, _ := filepath.Rel(s.workspaceDir, sanitizedPath)

	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     fileInfo.Size(),
		Mode:     fmt.Sprintf("%04o", fileInfo.Mode().Perm()),
		Modified: fileInfo.ModTime(),
	})
}

func (s *Server) handleJSONBase64Upload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid request body",
			"code":  400,
		})
		return
	}

	decoded, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid base64 encoding: %v", err),
			"code":  400,
		})
		return
	}

	mode := parseFileMode(req.Mode)

	sanitizedPath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directories: %v", err),
			"code":  500,
		})
		return
	}

	if err := os.WriteFile(sanitizedPath, decoded, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	fileInfo, _ := os.Stat(sanitizedPath)

	relPath, _ := filepath.Rel(s.workspaceDir, sanitizedPath)

	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     fileInfo.Size(),
		Mode:     fmt.Sprintf("%04o", fileInfo.Mode().Perm()),
		Modified: fileInfo.ModTime(),
	})
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' query parameter",
			"code":  400,
		})
		return
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "Directory not found",
				"code":  404,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to read directory: %v", err),
			"code":  500,
		})
		return
	}

	files := []FileEntry{}
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{
		Files: files,
	})
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")
	path = strings.TrimPrefix(path, "/")

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("access denied: %v", err),
			"code":  400,
		})
		return
	}

	fileInfo, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "File not found",
				"code":  404,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to stat file: %v", err),
			"code":  500,
		})
		return
	}

	if fileInfo.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is a directory, not a file",
			"code":  400,
		})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(sanitizedPath)))

	ext := filepath.Ext(sanitizedPath)
	mimeType := mime.TypeByExtension(ext)
	if mimeType == "" {
		mimeType = "application/octet-stream"
	}
	c.Header("Content-Type", mimeType)

	c.File(sanitizedPath)
}

func (s *Server) sanitizePath(p string) (string, error) {
	if s.workspaceDir == "" {
		return "", fmt.Errorf("workspace directory not initialized")
	}

	resolvedWorkspace, err := filepath.EvalSymlinks(s.workspaceDir)
	if err != nil {
		resolvedWorkspace = filepath.Clean(s.workspaceDir)
	}
	resolvedWorkspace = filepath.Clean(resolvedWorkspace)

	cleanPath := filepath.Clean(p)

	if filepath.IsAbs(cleanPath) {
		cleanPath = strings.TrimPrefix(cleanPath, string(filepath.Separator))
	}

	fullPathCandidate := filepath.Clean(filepath.Join(resolvedWorkspace, cleanPath))

	relPath, relErr := filepath.Rel(resolvedWorkspace, fullPathCandidate)
	if relErr != nil {
		return "", fmt.Errorf("access denied: path resolution error")
	}

	if strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
		return "", fmt.Errorf("access denied: path escapes workspace")
	}

	resolvedFinalPath, err := filepath.EvalSymlinks(fullPathCandidate)
	if err != nil {
		return fullPathCandidate, nil
	}

	relPath, relErr = filepath.Rel(resolvedWorkspace, resolvedFinalPath)
	if relErr != nil {
		return "", fmt.Errorf("access denied: symlink resolution error")
	}

	if strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
		return "", fmt.Errorf("access denied: symlink path escapes workspace")
	}

	return resolvedFinalPath, nil
}

func (s *Server) Run() error {
	s.httpServer = &http.Server{
		Addr:              fmt.Sprintf(":%d", s.config.Port),
		Handler:           s.engine,
		ReadHeaderTimeout: 10 * time.Second,
	}

	klog.Infof("Starting PicoD server on port %d", s.config.Port)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	return s.httpServer.Shutdown(ctx)
}

func setWorkspace(workspace string) (string, error) {
	if workspace != "" {
		absPath, err := filepath.Abs(workspace)
		if err != nil {
			absPath = workspace
		}
		return absPath, nil
	}

	cwd, err := os.Getwd()
	if err != nil {
		return "", fmt.Errorf("failed to get current working directory: %w", err)
	}

	return cwd, nil
}

func parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return defaultFileMode
	}

	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil {
		return defaultFileMode
	}

	if mode > uint64(maxFileMode) {
		return defaultFileMode
	}

	return os.FileMode(mode)
}

func envMapToSlice(envMap map[string]string) []string {
	env := make([]string, 0, len(envMap))
	for k, v := range envMap {
		env = append(env, fmt.Sprintf("%s=%s", k, v))
	}
	return env
}

